import sys

def solve(data: str) -> str:
    tokens = data.split()
    energy = int(tokens[0]); position = 0
    for action in tokens[1:]:
        if action == 'move':
            if energy <= 0:
                return 'invalid'
            energy -= 1; position += 1
        elif action == 'charge':
            energy += 1
        else:
            return 'invalid'
    return 'valid' if position >= 2 else 'invalid'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
